final:
module RefModule (
    input clk,
    input load,
    input [7:0] data_in,
    output reg [7:0] data_out
);
  wire _tap_clk = clk & {1{1'b1}};


always @(posedge clk) begin
    if (load) begin
        data_out <= data_in;
    end else begin
        data_out <= data_out << 1;
    end
end

endmodule
